/**
 * Popup 脚本
 * 
 * {{CORE_FEATURES}}
 */

document.addEventListener('DOMContentLoaded', function() {
  const actionBtn = document.getElementById('actionBtn');

  actionBtn.addEventListener('click', async () => {
    // TODO: 实现按钮点击逻辑
    const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });

    chrome.tabs.sendMessage(tab.id, { action: 'execute' }, (response) => {
      console.log('Response:', response);
    });
  });

  // 加载保存的设置
  chrome.storage.sync.get(['settings'], (result) => {
    if (result.settings) {
      console.log('Loaded settings:', result.settings);
    }
  });
});

/**
 * Background Service Worker
 * 
 * 处理扩展的后台逻辑
 */

// 监听扩展安装
chrome.runtime.onInstalled.addListener((details) => {
  if (details.reason === 'install') {
    console.log('{{PROJECT_NAME}} 已安装');
    // 初始化默认设置
    chrome.storage.sync.set({
      settings: {
        enabled: true,
        // TODO: 添加更多默认设置
      }
    });
  } else if (details.reason === 'update') {
    console.log('{{PROJECT_NAME}} 已更新');
  }
});

// 监听来自 content script 的消息
chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
  if (request.action === 'getData') {
    // TODO: 处理数据请求
    sendResponse({ data: null });
  }
  return true;
});

// 监听标签页更新
chrome.tabs.onUpdated.addListener((tabId, changeInfo, tab) => {
  if (changeInfo.status === 'complete') {
    // TODO: 处理页面加载完成事件
  }
});

/**
 * Content Script
 * 
 * 在网页中注入的脚本
 * 
 * {{DIFFERENTIATION}}
 */

(function() {
  'use strict';

  // 检查是否已注入
  if (window.__{{PROJECT_NAME}}_injected) return;
  window.__{{PROJECT_NAME}}_injected = true;

  console.log('{{PROJECT_NAME}} content script loaded');

  // 监听来自 popup 的消息
  chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
    if (request.action === 'execute') {
      // TODO: 实现页面操作逻辑
      executeMain();
      sendResponse({ success: true });
    }
    return true;
  });

  function executeMain() {
    // TODO: 实现核心功能
    console.log('Executing main function...');
  }

  // 初始化
  function init() {
    // TODO: 添加初始化逻辑
  }

  init();
})();

// 设置页面脚本

document.addEventListener('DOMContentLoaded', function() {
  // 加载设置
  chrome.storage.sync.get(['settings'], (result) => {
    if (result.settings) {
      document.getElementById('enabled').checked = result.settings.enabled;
    }
  });

  // 保存设置
  document.getElementById('save').addEventListener('click', () => {
    const settings = {
      enabled: document.getElementById('enabled').checked,
      // TODO: 保存其他设置
    };

    chrome.storage.sync.set({ settings }, () => {
      document.getElementById('status').textContent = '设置已保存！';
      setTimeout(() => {
        document.getElementById('status').textContent = '';
      }, 2000);
    });
  });
});

